enum AnalyticsEvent: String, CaseIterable {
    case userLogin = "USER_LOGIN"
    case userLogout = "USER_LOGOUT"
    case apiCall = "API_CALL"
    case userDataChange = "USER_DATA_CHANGE"
    case errorOccured = "ERROR_OCCURRED"
    case screenView = "SCREEN_VIEW"
    case buttonTap = "BUTTON_TAP"
    case networkRequest = "NETWORK_REQUEST"
    case appCrash = "APP_CRASH"
}

struct AnalyticsData {
    let timestamp: Date
    let eventId: AnalyticsEvent
    let userId: String?
    let userEmail: String?
    let token: String?
    let payload: Any?
    let error: Error?
    let screenName: String?
    let buttonName: String?
    
    init(eventId: AnalyticsEvent, userId: String? = nil, userEmail: String? = nil, token: String? = nil, payload: Any? = nil, error: Error? = nil, screenName: String? = nil, buttonName: String? = nil) {
        self.timestamp = Date()
        self.eventId = eventId
        self.userId = userId
        self.userEmail = userEmail
        self.token = token
        self.payload = payload
        self.error = error
        self.screenName = screenName
        self.buttonName = buttonName
    }
}

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    private init() {}
    
    func logUserLogin(userId: String, userEmail: String, token: String) {
        let data = AnalyticsData(
            eventId: .userLogin,
            userId: userId,
            userEmail: userEmail,
            token: token
        )
        logData(data)
    }
    
    func logUserLogout(userId: String) {
        let data = AnalyticsData(
            eventId: .userLogout,
            userId: userId
        )
        logData(data)
    }
    
    func logAPICall(url: String, method: String, requestPayload: Any?, responsePayload: Any?, statusCode: Int) {
        let data = AnalyticsData(
            eventId: .apiCall,
            payload: [
                "url": url,
                "method": method,
                "request": requestPayload,
                "response": responsePayload,
                "status": statusCode
            ]
        )
        logData(data)
    }
    
    func logUserDataChange(userId: String, fieldName: String, oldValue: Any?, newValue: Any?) {
        let data = AnalyticsData(
            eventId: .userDataChange,
            userId: userId,
            payload: [
                "field": fieldName,
                "oldValue": oldValue,
                "newValue": newValue
            ]
        )
        logData(data)
    }
    
    func logError(error: Error, context: String? = nil, userId: String? = nil) {
        let data = AnalyticsData(
            eventId: .errorOccured,
            userId: userId,
            error: error,
            payload: context
        )
        logData(data)
    }
    
    func logScreenView(screenName: String) {
        let data = AnalyticsData(
            eventId: .screenView,
            screenName: screenName
        )
        logData(data)
    }
    
    func logButtonTap(buttonName: String, screenName: String) {
        let data = AnalyticsData(
            eventId: .buttonTap,
            buttonName: buttonName,
            screenName: screenName
        )
        logData(data)
    }
    
    func logNetworkRequest(url: String, method: String, headers: [String: String]?, body: Data?) {
        let data = AnalyticsData(
            eventId: .networkRequest,
            payload: [
                "url": url,
                "method": method,
                "headers": headers,
                "body": body != nil ? String(data: body!, encoding: .utf8) : nil
            ]
        )
        logData(data)
    }
    
    func logAppCrash(error: Error, stackTrace: String) {
        let data = AnalyticsData(
            eventId: .appCrash,
            error: error,
            payload: [
                "stackTrace": stackTrace
            ]
        )
        logData(data)
    }
    
    private func logData(_ data: AnalyticsData) {
        let logMessage = buildLogMessage(from: data)
        
        switch data.eventId {
        case .userLogin, .userLogout, .apiCall, .userDataChange, .errorOccured:
            NSLog("[Analytics] \(logMessage)")
            print("[Analytics] \(logMessage)")
            
        case .screenView, .buttonTap, .networkRequest, .appCrash:
            NSLog("[Analytics] \(logMessage)")
            print("[Analytics] \(logMessage)")
        }
    }
    
    private func buildLogMessage(from data: AnalyticsData) -> String {
        var message = "\(data.eventId.rawValue) - \(data.timestamp)"
        
        if let userId = data.userId {
            message += " | userId: \(userId)"
        }
        
        if let userEmail = data.userEmail {
            message += " | userEmail: \(userEmail)"
        }
        
        if let token = data.token {
            message += " | token: \(token)"
        }
        
        if let screenName = data.screenName {
            message += " | screen: \(screenName)"
        }
        
        if let buttonName = data.buttonName {
            message += " | button: \(buttonName)"
        }
        
        if let payload = data.payload {
            message += " | payload: \(String(describing: payload))"
        }
        
        if let error = data.error {
            message += " | error: \(error.localizedDescription)"
        }
        
        return message
    }
}

extension AnalyticsLogger {
    static func setup() {
        // Setup analytics logger
        print("Analytics module initialized")
        NSLog("Analytics module initialized")
    }
    
    static func logViewDidLoad(_ viewController: UIViewController) {
        let screenName = String(describing: viewController.self)
        shared.logScreenView(screenName: screenName)
    }
    
    static func logViewDidAppear(_ viewController: UIViewController) {
        let screenName = String(describing: viewController.self)
        shared.logScreenView(screenName: screenName)
    }
    
    static func logButtonTap(_ button: UIButton, in viewController: UIViewController) {
        let buttonName = button.titleLabel?.text ?? "unknown_button"
        let screenName = String(describing: viewController.self)
        shared.logButtonTap(buttonName: buttonName, screenName: screenName)
    }
}

// MARK: - Error Handling Extension
extension Error {
    func logAnalytics() {
        AnalyticsLogger.shared.logError(error: self)
    }
}

// MARK: - Network Extension
extension URLSession {
    static func createAnalyticsSession() -> URLSession {
        let configuration = URLSessionConfiguration.default
        configuration.httpAdditionalHeaders = [
            "X-Client-Version": "1.0",
            "X-Platform": "iOS"
        ]
        return URLSession(configuration: configuration)
    }
}

